import heapq

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    adj = [[] for _ in range(n)]
    for u, v, cost in edges:
        adj[u].append((v, cost))

    best_min = [-1] * n
    best_min[0] = float('inf')

    heap = [(-float('inf'), 0, 0)]

    while heap:
        neg_curr_min, total_cost, u = heapq.heappop(heap)
        curr_min = -neg_curr_min

        if u == n - 1:
            return curr_min

        if curr_min < best_min[u]:
            continue

        for v, cost in adj[u]:
            if not online[v]:
                continue
            new_min = min(curr_min, cost)
            new_total = total_cost + cost
            if new_total > k:
                continue
            if new_min > best_min[v]:
                best_min[v] = new_min
                heapq.heappush(heap, (-new_min, new_total, v))

    return -1
